use aiken/primitive/string
use cardano/transaction.{OutputReference, Transaction}

pub type TagDatum {
  tag: ByteArray,
  value: Int,
}

fn is_non_empty_bytearray(bytes: ByteArray) -> Bool {
  bytes != #""
}

validator tagged_output {
  spend(
    datum: Option<TagDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let tag_string = string.from_bytearray(d.tag)
        let value_string = string.from_int(d.value)
        let label = string.concat(tag_string, value_string)
        let tag_bytes = string.to_bytearray(tag_string)
        let label_bytes = string.to_bytearray(label)
        is_non_empty_bytearray(tag_bytes) && is_non_empty_bytearray(label_bytes)
      }
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/dict
use aiken/primitive/string
use cardano/assets.{PolicyId}
