pub type MintRedeemer {
  sequence_number: Int,
}

fn build_token_name(seq: Int) -> ByteArray {
  let name_str = string.concat(@"token_", string.from_int(seq))
  string.to_bytearray(name_str)
}

validator labeled_mint {
  mint(redeemer: MintRedeemer, policy_id: PolicyId, self: Transaction) -> Bool {
    let expected_name = build_token_name(redeemer.sequence_number)

    let minted = self.mint

    let policy_tokens =
      minted
        |> assets.tokens(policy_id)

    let has_expected_token =
      policy_tokens
        |> dict.has_key(expected_name)

    has_expected_token
  }

  else(_) {
    fail
  }
}

