use aiken/primitive/string
use cardano/transaction.{OutputReference, Transaction}

pub type MessageDatum {
  greeting: ByteArray,
  name: ByteArray,
  separator: ByteArray,
}

fn build_message(datum: MessageDatum) -> String {
  let greeting_str = string.from_bytearray(datum.greeting)
  let separator_str = string.from_bytearray(datum.separator)
  let name_str = string.from_bytearray(datum.name)
  let with_sep = string.concat(greeting_str, separator_str)
  string.concat(with_sep, name_str)
}

validator message_builder {
  spend(
    datum: Option<MessageDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let full_message = build_message(d)
        let message_bytes = string.to_bytearray(full_message)
        (message_bytes != #"")
      }
    }
  }
}

