use aiken/collection/dict
use aiken/primitive/string
use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}

pub type MintRedeemer {
  prefix: ByteArray,
  seq: Int,
}

fn build_asset_name(prefix: ByteArray, seq: Int) -> ByteArray {
  let prefix_str = string.from_bytearray(prefix)
  let seq_str = string.from_int(seq)
  let combined = string.concat(prefix_str, seq_str)
  string.to_bytearray(combined)
}

validator prefixed_token_mint {
  mint(redeemer: MintRedeemer, policy_id: PolicyId, self: Transaction) -> Bool {
    let expected_asset_name = build_asset_name(redeemer.prefix, redeemer.seq)

    let minted = self.mint

    let policy_assets =
      minted
        |> assets.tokens(policy_id)

    let minted_correct_token =
      dict.foldr(
        policy_assets,
        False,
        fn(asset_name, quantity, acc) {
          if asset_name == expected_asset_name {
            quantity > 0 || acc
          } else {
            acc
          }
        },
      )

    minted_correct_token
  }

  else(_) {
    fail
  }
}

