use aiken/collection/list
use aiken/crypto.{blake2b_256}
use aiken/primitive/string
use cardano/transaction.{OutputReference, Transaction}

pub type JoinDatum {
  parts: List<ByteArray>,
  separator: ByteArray,
  expected_hash: ByteArray,
}

fn verify_join(
  parts: List<ByteArray>,
  separator: ByteArray,
  expected_hash: ByteArray,
) -> Bool {
  let string_parts = list.map(parts, fn(b) { string.from_bytearray(b) })
  let sep_string = string.from_bytearray(separator)
  let joined_string = string.join(string_parts, sep_string)
  let joined_bytes = string.to_bytearray(joined_string)
  let result_hash = blake2b_256(joined_bytes)
  result_hash == expected_hash
}

validator join_validator {
  spend(
    datum: Option<JoinDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> verify_join(d.parts, d.separator, d.expected_hash)
    }
  }

  else(_) {
    False
  }
}

