pub type RegistryDatum {
  id: Int,
  owner: ByteArray,
}

fn build_label(label_prefix: ByteArray, id: Int) -> String {
  string.concat(string.from_bytearray(label_prefix), string.from_int(id))
}

fn owner_signed(self: Transaction, owner: ByteArray) -> Bool {
  list.has(self.extra_signatories, owner)
}

validator labeled_registry(label_prefix: ByteArray) {
  spend(
    datum: Option<RegistryDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let _label = build_label(label_prefix, d.id)
        owner_signed(self, d.owner)
      }
    }
  }

  else(_) -> Bool {
    False
  }
}

use aiken/primitive/bytearray
use aiken/primitive/string
use cardano/transaction.{OutputReference, Transaction}

pub type NameDatum {
  name_bytes: ByteArray,
  min_len: Int,
}

validator name_length_check {
  spend(
    datum: Option<NameDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let name_string = string.from_bytearray(d.name_bytes)
        let name_back = string.to_bytearray(name_string)
        let length = bytearray.length(name_back)
        length >= d.min_len
      }
    }
  }

  else(_) -> Bool {
    False
  }
}
